void main() {
  int? nullableInt = null;
  print(nullableInt?.isEven);   // null (safe access)

  int value = nullableInt ?? 42; // default to 42
  print(value);                  // 42

  nullableInt ??= 100;            // assigns 100 because it was null
  print(nullableInt);             // 100

  // The following would throw an error:
  // print(nullableInt!.isEven);  // works now, but risky
}
